#include <stdio.h>
#include <stdlib.h>

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    double **prob = (double **)malloc(N * sizeof(double *));
    for (int i = 0; i < N; i++) {
        prob[i] = (double *)malloc(K * sizeof(double));
    }
    for (int i = 0; i < N; i++) {
        int sum = 0;
        for (int j = 0; j < K; j++) {
            int x;
            scanf("%d", &x);
            sum += x;
            prob[i][j] = (double)x / sum;
        }
    }
    for (int i = 1; i < N; i++) {
        for (int j = 0; j < K; j++) {
            double sum = 0;
            for (int k = 0; k < K; k++) {
                sum += prob[i - 1][k] * prob[i][j];
            }
            prob[i][j] = sum;
        }
    }
    for (int i = 0; i < K; i++) {
        printf("%f ", prob[N - 1][i]);
    }
    return 0;
}

