                int x = sc.nextInt();
                sum += x;
                prob[i][j] = (double)x / sum;
            }
        }
        for (int i = 1; i < N; i++) {
            for (int j = 0; j < K; j++) {
                double sum = 0;
                for (int k = 0; k < K; k++) {
                    sum += prob[i - 1][k] * prob[i][j];
                }
                prob[i][j] = sum;
            }
        }
        for (int i = 0; i < K; i++) {
