const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const [N, K] = readline().split(' ').map(Number);
const prob = Array(N).fill(0).map(() => Array(K).fill(0));
for (let i = 0; i < N; i++) {
    const row = readline().split(' ').map(Number);
    const total = row.reduce((a, b) => a + b, 0);
    for (let j = 0; j < K; j++) {
        prob[i][j] = row[j] / total;
    }
}
for (let i = 1; i < N; i++) {
    for (let j = 0; j < K; j++) {
        let total = 0;
        for (let k = 0; k < K; k++) {
            total += prob[i - 1][k] * prob[i][j];
        }
        prob[i][j] = total;
    }
}
